SELECT DISTINCT
    DATE_FORMAT(record_time,'%Y-%m')
FROM
    record
WHERE
    (user_id = #{userId} OR user_id IN (
        SELECT user_id FROM family
        WHERE group_id = (
            SELECT group_id FROM family WHERE user_id = #{userId}
        )
          AND user_id != #{userId}
        )
    )
ORDER BY DATE_FORMAT(record_time,'%Y-%m') ASC

SELECT DISTINCT
    DATE_FORMAT(record_time,'%Y')
FROM
    record
WHERE
    (user_id = #{userId} OR user_id IN (
        SELECT user_id FROM family
        WHERE group_id = (
            SELECT group_id FROM family WHERE user_id = #{userId}
        )
          AND user_id != #{userId}
        )
    )
ORDER BY DATE_FORMAT(record_time,'%Y') ASC

SELECT
    SUM( r.amount ) AS amount,
    r.category_name,
    r.category_icon,
    ROUND( SUM( r.amount ) / total.total_amount * 100, 2 ) AS percent
FROM
    record r
        INNER JOIN ( SELECT SUM( amount ) AS total_amount FROM record WHERE (user_id = #{userId} OR user_id IN (
        SELECT user_id FROM family
        WHERE group_id = (
            SELECT group_id FROM family WHERE user_id = #{userId}
        )
          AND user_id != #{userId}
                                                                                )
    ) AND record_type = #{recordType} AND record_time LIKE CONCAT( #{time}, '%' ) ) total ON 1 = 1
WHERE
    (r.user_id = #{userId} OR r.user_id IN (
        SELECT user_id FROM family
        WHERE group_id = (
            SELECT group_id FROM family WHERE user_id = #{userId}
        )
          AND user_id != #{userId}
        )
    )
  AND r.record_type = #{recordType}
  AND r.record_time LIKE CONCAT( #{time}, '%' )
GROUP BY
    r.category_name
ORDER BY
    SUM( r.amount ) DESC;

SELECT
    SUM( CASE WHEN record_type = 2 THEN amount ELSE 0 END ) income,
    SUM( CASE WHEN record_type = 1 THEN amount ELSE 0 END ) expense
FROM
    record
WHERE
    (user_id = #{userId} OR user_id IN (
        SELECT user_id FROM family
        WHERE group_id = (
            SELECT group_id FROM family WHERE user_id = #{userId}
        )
          AND user_id != #{userId}
        )
    )
  AND record_time LIKE CONCAT( #{month}, '%' )
